CREATE TABLE IF NOT EXISTS catalog_stock_items (
  id              SERIAL PRIMARY KEY,
  code            TEXT NOT NULL UNIQUE,
  name            TEXT NOT NULL,
  category        TEXT,
  clinic_type     TEXT,
  presentation    TEXT,
  frequency_class TEXT
);

ALTER TABLE catalog_stock_items ENABLE ROW LEVEL SECURITY;
CREATE POLICY "catalog_stock_read" ON catalog_stock_items
  FOR SELECT USING (auth.role() = 'authenticated');

CREATE INDEX IF NOT EXISTS idx_catalog_stock_name ON catalog_stock_items USING gin(to_tsvector('portuguese', name));
CREATE INDEX IF NOT EXISTS idx_catalog_stock_cat  ON catalog_stock_items(category);


